# ── CELL 7: Strategy Efficiency Chart ───────────────────────
fig, axes = plt.subplots(1, 2, figsize=(14, 6))

tiers   = ['HIGH RISK', 'MEDIUM RISK', 'LOW RISK']
recover = [65, 42, 15]
effort  = [40, 35, 25]
cols    = ['#e74c3c', '#f39c12', '#2ecc71']

# Recovery rate
